svg.script:

const gameObjects = document.getElementById('game-objects');
const scoreEl = document.getElementById('score');
const overlay = document.getElementById('overlay');

const GRID_SIZE = 20;
const TILE_COUNT = 20; // 400px / 20px

let score = 0;
let gameActive = false;
let snake = [{x: 10, y: 10}, {x: 9, y: 10}, {x: 8, y: 10}];
let food = {x: 15, y: 15};
let dx = 1;
let dy = 0;
let nextDx = 1;
let nextDy = 0;
let gameLoop = null;

function createRect(x, y, color) {
    const rect = document.createElementNS("http://www.w3.org/2000/svg", "rect");
    rect.setAttribute('x', x * GRID_SIZE);
    rect.setAttribute('y', y * GRID_SIZE);
    rect.setAttribute('width', GRID_SIZE - 2);
    rect.setAttribute('height', GRID_SIZE - 2);
    rect.setAttribute('rx', '2');
    rect.setAttribute('fill', color);
    return rect;
}

function updateView() {
    gameObjects.innerHTML = '';

    // Draw Food
    const foodRect = createRect(food.x, food.y, '#e74c3c');
    gameObjects.appendChild(foodRect);

    // Draw Snake
    snake.forEach((seg, i) => {
        const color = i === 0 ? '#2ecc71' : '#27ae60';
        gameObjects.appendChild(createRect(seg.x, seg.y, color));
    });

    scoreEl.textContent = score;
}

function moveSnake() {
    dx = nextDx;
    dy = nextDy;

    const head = {x: snake[0].x + dx, y: snake[0].y + dy};

    // Wall collision
    if (head.x < 0 || head.x >= TILE_COUNT || head.y < 0 || head.y >= TILE_COUNT) {
        return gameOver();
    }

    // Self collision
    for (let i = 0; i < snake.length; i++) {
        if (snake[i].x === head.x && snake[i].y === head.y) return gameOver();
    }

    snake.unshift(head);

    // Food collision
    if (head.x === food.x && head.y === food.y) {
        score += 10;
        spawnFood();
    } else {
        snake.pop();
    }

    updateView();
}

function spawnFood() {
    let newFood;
    while (true) {
        newFood = {
            x: Math.floor(Math.random() * TILE_COUNT),
            y: Math.floor(Math.random() * TILE_COUNT)
        };
        // Check if food spawned on snake
        if (!snake.some(seg => seg.x === newFood.x && seg.y === newFood.y)) break;
    }
    food = newFood;
}

function gameOver() {
    gameActive = false;
    clearInterval(gameLoop);
    overlay.setAttribute('visibility', 'visible');
    overlay.querySelector('text').textContent = "GAME OVER!";
}

window.addEventListener('keydown', (e) => {
    if (!gameActive) return;

    if (e.key === 'ArrowUp' && dy === 0) { nextDx = 0; nextDy = -1; }
    else if (e.key === 'ArrowDown' && dy === 0) { nextDx = 0; nextDy = 1; }
    else if (e.key === 'ArrowLeft' && dx === 0) { nextDx = -1; nextDy = 0; }
    else if (e.key === 'ArrowRight' && dx === 0) { nextDx = 1; nextDy = 0; }

    if (['ArrowUp', 'ArrowDown', 'ArrowLeft', 'ArrowRight'].includes(e.key)) {
        e.preventDefault();
    }
    if (e.key.toLowerCase() === 'r') {
        restartGame();
    }
});

function restartGame() {
    snake = [{x: 10, y: 10}, {x: 9, y: 10}, {x: 8, y: 10}];
    dx = 1; dy = 0; nextDx = 1; nextDy = 0;
    score = 0;
    gameActive = true;
    overlay.setAttribute('visibility', 'hidden');
    spawnFood();
    updateView();
    if (gameLoop) clearInterval(gameLoop);
    gameLoop = setInterval(moveSnake, 120);
}

overlay.addEventListener('click', () => {
    restartGame();
});

updateView();
